  $c3='C003FF'
  $rasd.VirtualPortWWNN='2000'+$c3+'00000000'
  $rasd.VirtualPortWWPN='1001'+$c3+'0EA00001'
  $rasd.SecondaryWWNN ='2000'+$c3+'00000000'
